import { ref, reactive, onActivated, onMounted, nextTick } from 'vue'
import { ElMessage, ElMessageBox } from 'element-plus'
import { MsgBox } from '@/util/msgutil/msgBox.js'
import { Plus, Edit, Delete, Download } from '@element-plus/icons-vue'
import { request } from '@/util/globalContext'
import { listCommon } from '@/util/vueutil/commonList.js'
import * as XLSX from 'xlsx'

const PAYMENT_STATUS_OPTIONS = [
    { code: '0', label: '待缴费', type: 'warning' },
    { code: '1', label: '已缴费', type: 'success' },
    { code: '2', label: '未缴全', type: 'danger' }
]

export default function useRentRecordList() {
    const listRef = ref(null)
    const dialogVisible = ref(false)
    const dialogType = ref('add')
    const formRef = ref(null)

    const Options = ref({
        paymentStatusOptions: PAYMENT_STATUS_OPTIONS
    })

    const searchForm = reactive({
        contractNo: '',
        tenantName: '',
        paymentStatus: '',
        dateRange: [],
        showAll: false
    })

    const {
        listShow,
        handleReset,
        handleSelectionChange,
        handleCurrentRowChange
    } = listCommon(searchForm)

    const FORM_DEFAULT = {
        id: '',
        serialNo: '',
        contractNo: '',
        rentPeriodStart: '',
        rentPeriodEnd: '',
        rentDueDate: '',
        actualPayDate: '',
        rentAmount: '',
        waterPreviousReading: '',
        waterCurrentReading: '',
        waterFee: '',
        electricityPreviousReading: '',
        electricityCurrentReading: '',
        electricityFee: '',
        miscFee: '',
        totalAmount: '',
        paidAmount: '',
        remainingAmount: '',
        paymentStatus: '0',
        tenantName: '',
        tenantPhone: '',
        houseInfo: '',
        remark: ''
    }

    const formData = reactive({ ...FORM_DEFAULT })

    const formRules = {
        contractNo: [
            { required: true, message: '请输入合同号', trigger: 'blur,change' }
        ],
        rentPeriodStart: [
            { required: true, message: '请选择交租周期开始日期', trigger: 'change' }
        ],
        rentPeriodEnd: [
            { required: true, message: '请选择交租周期结束日期', trigger: 'change' }
        ],
        rentDueDate: [
            { required: true, message: '请选择最晚交租日', trigger: 'change' }
        ],
        paymentStatus: [
            { required: true, message: '请选择缴费状态', trigger: 'change' }
        ]
    }

    const getStatusType = (status) => {
        return PAYMENT_STATUS_OPTIONS.find(item => item.code === status)?.type || 'info'
    }

    const calculateTotalAmount = () => {
        const rentAmount = parseFloat(formData.rentAmount) || 0
        const waterFee = parseFloat(formData.waterFee) || 0
        const electricityFee = parseFloat(formData.electricityFee) || 0
        const miscFee = parseFloat(formData.miscFee) || 0
        formData.totalAmount = (rentAmount + waterFee + electricityFee + miscFee).toFixed(2)
        calculateRemainingAmount()
    }

    const calculateRemainingAmount = () => {
        const totalAmount = parseFloat(formData.totalAmount) || 0
        const paidAmount = parseFloat(formData.paidAmount) || 0
        formData.remainingAmount = (totalAmount - paidAmount).toFixed(2)
        
        if (parseFloat(formData.remainingAmount) <= 0 && parseFloat(formData.paidAmount) > 0) {
            formData.paymentStatus = '1'
        } else if (parseFloat(formData.paidAmount) > 0) {
            formData.paymentStatus = '2'
        } else {
            formData.paymentStatus = '0'
        }
    }

    const handleLoadList = async (paginationParams) => {
        if (!listRef.value) return
        if (!listRef.value.isInited) {
            await nextTick()
            if (!listRef.value?.isInited) {
                ElMessage.warning('列表组件初始化中，请稍后重试')
                return
            }
        }

        listRef.value?.setLoading(true)
        try {
            const params = {
                ...paginationParams,
                contractNo: searchForm.contractNo,
                tenantName: searchForm.tenantName,
                paymentStatus: searchForm.paymentStatus,
                startDate: searchForm.dateRange[0] || '',
                endDate: searchForm.dateRange[1] || '',
                showAll: searchForm.showAll
            }
            const res = await request.get('/rent/record/getPage', { params })
            if (listRef.value) {
                if (res.code === 200) {
                    listRef.value.updateListData(res.data.records || [])
                    listRef.value.updatePagination({
                        pageNum: paginationParams.pageNum,
                        pageSize: paginationParams.pageSize,
                        total: res.data.total || 0
                    })
                } else {
                    ElMessage.error('列表加载失败：' + (res.msg || '接口异常'))
                    listRef.value.updateListData([])
                    listRef.value.updatePagination({ ...paginationParams, total: 0 })
                }
            }
        } catch (error) {
            ElMessage.error('列表加载失败：网络异常')
            if (listRef.value) {
                listRef.value.updateListData([])
                listRef.value.updatePagination({ ...paginationParams, total: 0 })
            }
        } finally {
            listRef.value?.setLoading(false)
        }
    }

    const handleAdd = () => {
        dialogType.value = 'add'
        formRef.value?.resetFields()
        Object.assign(formData, JSON.parse(JSON.stringify(FORM_DEFAULT)))
        dialogVisible.value = true
    }

    const handleEdit = async () => {
        if (!listShow.value || listShow.value.length !== 1) {
            ElMessage.warning('请先选中一条数据！')
            return
        }
        if (!listRef.value?.isInited) {
            ElMessage.warning('列表组件初始化中，请稍后重试')
            return
        }

        try {
            listRef.value?.setLoading(true)
            const res = await request.get('/rent/record/getDetail', { params: { id: listShow.value[0].id } })
            if (res.code !== 200) {
                ElMessage.error(res.msg || '接口异常')
                return
            }
            const data = res.data
            Object.assign(formData, JSON.parse(JSON.stringify(FORM_DEFAULT)))
            formData.id = data.id || ''
            formData.serialNo = data.serialNo || ''
            formData.contractNo = data.contractNo || ''
            formData.rentPeriodStart = data.rentPeriodStart
            formData.rentPeriodEnd = data.rentPeriodEnd
            formData.rentDueDate = data.rentDueDate
            formData.actualPayDate = data.actualPayDate
            formData.rentAmount = data.rentAmount
            formData.waterPreviousReading = data.waterPreviousReading
            formData.waterCurrentReading = data.waterCurrentReading
            formData.waterFee = data.waterFee
            formData.electricityPreviousReading = data.electricityPreviousReading
            formData.electricityCurrentReading = data.electricityCurrentReading
            formData.electricityFee = data.electricityFee
            formData.miscFee = data.miscFee
            formData.totalAmount = data.totalAmount
            formData.paidAmount = data.paidAmount
            formData.remainingAmount = data.remainingAmount
            formData.paymentStatus = data.paymentStatus
            formData.tenantName = data.tenantName || ''
            formData.tenantPhone = data.tenantPhone || ''
            formData.houseInfo = data.houseInfo || ''
            formData.remark = data.remark || ''

            dialogType.value = 'edit'
            dialogVisible.value = true
        } catch (error) {
            ElMessage.error('获取详情失败：' + error)
        } finally {
            listRef.value?.setLoading(false)
        }
    }

    const handleDelete = async () => {
        if (!listShow.value || listShow.value.length === 0) {
            ElMessage.warning('请先选中数据！')
            return
        }
        try {
            await ElMessageBox.confirm(
                '确定删除选中的' + listShow.value.length + '条数据？',
                '删除确认',
                { confirmButtonText: '确定', cancelButtonText: '取消', type: 'warning' }
            )

            listRef.value?.setLoading(true)
            const ids = listShow.value.map(item => item.id)
            const params = { ids: ids }
            const res = await request.post('/rent/record/delBatch', params)
            if (listRef.value) {
                if (res.code === 200) {
                    ElMessage.success('删除成功')
                    const pagination = listRef.value.getPagination()
                    handleLoadList(pagination)
                } else {
                    MsgBox.warning2('删除失败：' + (res.msg || '接口异常'))
                }
            }
        } catch (error) {
            if (error !== 'cancel') {
                ElMessage.error('删除失败：网络异常')
            }
        } finally {
            listRef.value?.setLoading(false)
        }
    }

    const handleExport = () => {
        if (!listShow.value || listShow.value.length === 0) {
            ElMessage.warning('请先选择要导出的数据！')
            return
        }

        try {
            const paymentStatusMap = {
                '0': '待缴费',
                '1': '已缴费',
                '2': '未缴全'
            }

            const exportData = listShow.value.map(item => {
                const amountDetail = `租金:${item.rentAmount || 0}元, 水费:${item.waterFee || 0}元, 电费:${item.electricityFee || 0}元, 杂费:${item.miscFee || 0}元`
                return {
                    '订单号': item.serialNo || '',
                    '租房人': item.tenantName || '',
                    '租房人手机号': item.tenantPhone || '',
                    '房屋信息': item.houseInfo || '',
                    '交租日期': item.rentPeriodStart ? item.rentPeriodStart + ' 至 ' + item.rentPeriodEnd : '',
                    '金额信息': item.totalAmount || 0,
                    '金额详情': amountDetail,
                    '缴费状态': paymentStatusMap[item.paymentStatus] || '',
                    '最晚交租日': item.rentDueDate || ''
                }
            })

            const worksheet = XLSX.utils.json_to_sheet(exportData)
            const workbook = XLSX.utils.book_new()
            XLSX.utils.book_append_sheet(workbook, worksheet, '收租记录')

            worksheet['!cols'] = [
                { wch: 22 },
                { wch: 12 },
                { wch: 16 },
                { wch: 20 },
                { wch: 24 },
                { wch: 10 },
                { wch: 40 },
                { wch: 10 },
                { wch: 12 }
            ]

            const fileName = '收租记录_' + new Date().toLocaleDateString('zh-CN').replace(/\//g, '-') + '.xlsx'
            XLSX.writeFile(workbook, fileName)
            ElMessage.success('导出成功！')
        } catch (error) {
            ElMessage.error('导出失败：' + error.message)
        }
    }

    const handleSubmit = async () => {
        if (!formRef.value) return

        const isValid = await new Promise((resolve) => {
            formRef.value.validate((valid) => {
                resolve(valid)
            })
        })
        if (!isValid) return

        const submitData = {
            id: dialogType.value === 'edit' ? formData.id : '',
            contractNo: formData.contractNo,
            rentPeriodStart: formData.rentPeriodStart,
            rentPeriodEnd: formData.rentPeriodEnd,
            rentDueDate: formData.rentDueDate,
            actualPayDate: formData.actualPayDate,
            rentAmount: parseFloat(formData.rentAmount) || 0,
            waterPreviousReading: parseFloat(formData.waterPreviousReading) || null,
            waterCurrentReading: parseFloat(formData.waterCurrentReading) || null,
            waterFee: parseFloat(formData.waterFee) || 0,
            electricityPreviousReading: parseFloat(formData.electricityPreviousReading) || null,
            electricityCurrentReading: parseFloat(formData.electricityCurrentReading) || null,
            electricityFee: parseFloat(formData.electricityFee) || 0,
            miscFee: parseFloat(formData.miscFee) || 0,
            totalAmount: parseFloat(formData.totalAmount) || 0,
            paidAmount: parseFloat(formData.paidAmount) || 0,
            remainingAmount: parseFloat(formData.remainingAmount) || 0,
            paymentStatus: formData.paymentStatus,
            tenantName: formData.tenantName,
            tenantPhone: formData.tenantPhone,
            houseInfo: formData.houseInfo,
            remark: formData.remark
        }

        if (dialogType.value === 'edit') {
            submitData.serialNo = formData.serialNo
        }

        listRef.value?.setLoading(true)
        try {
            const res = await request.post('/rent/record/saveOrUpdate', submitData)
            if (listRef.value) {
                if (res.code === 200) {
                    ElMessage.success(dialogType.value === 'add' ? '新增成功' : '修改成功')
                    dialogVisible.value = false
                    const pagination = listRef.value.getPagination()
                    handleLoadList(pagination)
                } else {
                    const tip = dialogType.value === 'add' ? '新增失败' : '修改失败'
                    ElMessage.error(tip + '：' + (res.msg || '接口异常'))
                }
            }
        } catch (error) {
            ElMessage.error('接口异常：' + error)
        } finally {
            listRef.value?.setLoading(false)
        }
    }

    onMounted(async () => {
        await nextTick()
        setTimeout(() => {
            if (listRef.value?.isInited) {
                const pagination = listRef.value.getPagination()
                handleLoadList(pagination)
            }
        }, 50)
    })

    onActivated(async () => {
        if (listRef.value?.isInited) {
            const pagination = listRef.value.getPagination()
            handleLoadList(pagination)
        }
    })

    return {
        searchForm,
        listRef,
        dialogType,
        formRef,
        listShow,
        formData,
        formRules,
        Plus, Edit, Delete, Download,
        handleSelectionChange,
        handleCurrentRowChange,
        handleAdd,
        handleEdit,
        handleDelete,
        handleExport,
        handleSubmit,
        handleLoadList,
        handleReset,
        dialogVisible,
        Options,
        getStatusType,
        calculateTotalAmount,
        calculateRemainingAmount
    }
}
